                end if; 
            end if;
        end if;
    end process;


    ap_rst_n_inv_assign_proc : process (ap_clk)
    begin
        if (ap_clk'event and ap_clk = '1') then
            ap_rst_n_inv <= ap_rst_reg_1;
        end if;
    end process;

    ap_rst_reg_1_assign_proc : process (ap_clk)
    begin
        if (ap_clk'event and ap_clk = '1') then
            ap_rst_reg_1 <= ap_rst_reg_2;
        end if;
    end process;

    ap_rst_reg_2_assign_proc : process (ap_clk)
    begin
        if (ap_clk'event and ap_clk = '1') then
                        ap_rst_reg_2 <= not(ap_rst_n);
        end if;
    end process;
    ap_done <= ap_sync_done;
    ap_idle <= (write_U0_ap_idle and write_2_U0_ap_idle and read_U0_ap_idle and read_1_U0_ap_idle);
    ap_ready <= ap_sync_ready;
    ap_sync_continue <= (ap_sync_done and ap_continue);
    ap_sync_done <= (write_U0_ap_done and write_2_U0_ap_done);
    ap_sync_read_1_U0_ap_ready <= (read_1_U0_ap_ready or ap_sync_reg_read_1_U0_ap_ready);
    ap_sync_read_U0_ap_ready <= (read_U0_ap_ready or ap_sync_reg_read_U0_ap_ready);
    ap_sync_ready <= (ap_sync_read_U0_ap_ready and ap_sync_read_1_U0_ap_ready);
    mem_0_0_BID <= ap_const_lv1_0;
    mem_0_0_BRESP <= ap_const_lv2_0;
    mem_0_0_BUSER <= ap_const_lv1_0;
    mem_0_0_RID <= ap_const_lv1_0;
    mem_0_0_RLAST <= ap_const_logic_0;
    mem_0_0_RRESP <= ap_const_lv2_0;
    mem_0_0_RUSER <= ap_const_lv1_0;
    mem_1_0_BID <= ap_const_lv1_0;
    mem_1_0_BRESP <= ap_const_lv2_0;
    mem_1_0_BUSER <= ap_const_lv1_0;
    mem_1_0_RID <= ap_const_lv1_0;
    mem_1_0_RLAST <= ap_const_logic_0;
    mem_1_0_RRESP <= ap_const_lv2_0;
    mem_1_0_RUSER <= ap_const_lv1_0;
    read_1_U0_ap_continue <= ap_const_logic_1;
    read_1_U0_ap_start <= ((ap_sync_reg_read_1_U0_ap_ready xor ap_const_logic_1) and ap_start and ap_const_logic_1);
    read_U0_ap_continue <= ap_const_logic_1;
    read_U0_ap_start <= ((ap_sync_reg_read_U0_ap_ready xor ap_const_logic_1) and ap_start and ap_const_logic_1);
    start_for_write_2_U0_din <= (0=>ap_const_logic_1, others=>'-');
    start_for_write_U0_din <= (0=>ap_const_logic_1, others=>'-');
    write_2_U0_ap_continue <= ap_sync_continue;
    write_2_U0_ap_start <= start_for_write_2_U0_empty_n;
    write_U0_ap_continue <= ap_sync_continue;
